package com.corporativoalpha.catalogservice.controllers;import com.corporativoalpha.catalogservice.models.Space;import com.corporativoalpha.catalogservice.services.SpaceService;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController@RequestMapping("/api/spaces")@Tag(name = "Spaces", description = "Endpoints para la gestion de salas y escritorios")public class SpaceController {private final SpaceService spaceService;public SpaceController(SpaceService spaceService){this.spaceService=spaceService;}@GetMapping@Operation(summary = "Obtener todos los espacios")public List<Space> getAllSpaces(){return spaceService.getAllSpaces();}@GetMapping("/{id}")@Operation(summary = "Obtener un espacio por ID")public ResponseEntity<Space> getSpaceById(@PathVariable Long id){return spaceService.getSpaceById(id).map(ResponseEntity::ok).orElse(ResponseEntity.notFound().build());}@PostMapping@Operation(summary = "Crear un nuevo espacio (Solo ADMIN)")public ResponseEntity<Space> createSpace(@RequestBody Space space){return ResponseEntity.status(HttpStatus.CREATED).body(spaceService.createSpace(space));}@PutMapping("/{id}")@Operation(summary = "Actualizar un espacio existente (Solo ADMIN)")public ResponseEntity<Space> updateSpace(@PathVariable Long id,@RequestBody Space spaceDetails){try{return ResponseEntity.ok(spaceService.updateSpace(id,spaceDetails));}catch(RuntimeException e){return ResponseEntity.notFound().build();}}@DeleteMapping("/{id}")@Operation(summary = "Eliminar un espacio (Solo ADMIN)")public ResponseEntity<Void> deleteSpace(@PathVariable Long id){try{spaceService.deleteSpace(id);return ResponseEntity.noContent().build();}catch(RuntimeException e){return ResponseEntity.notFound().build();}}}
